<?php
declare(strict_types=1);
namespace App\Recruit\Transport\Controller\Api\V1\Resume;
use App\Recruit\Domain\Entity\Resume;use App\Recruit\Infrastructure\Repository\ResumeRepository;use App\User\Domain\Entity\User;use Ramsey\Uuid\Uuid;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpKernel\Attribute\AsController;use Symfony\Component\HttpKernel\Exception\HttpException;use Symfony\Component\Routing\Attribute\Route;use Symfony\Component\Security\Core\Authorization\Voter\AuthenticatedVoter;use Symfony\Component\Security\Http\Attribute\IsGranted;
#[AsController] #[IsGranted(AuthenticatedVoter::IS_AUTHENTICATED_FULLY)] final readonly class MyResumeActivateController { public function __construct(private ResumeRepository $resumeRepository){}
#[Route(path:'/v1/recruit/private/me/resumes/{resumeId}/activate',methods:[Request::METHOD_POST])] public function __invoke(string $resumeId, User $loggedInUser): JsonResponse { if(!Uuid::isValid($resumeId)) throw new HttpException(400,'Invalid resumeId'); $resume=$this->resumeRepository->find($resumeId); if(!$resume instanceof Resume) throw new HttpException(404,'Resume not found.'); if($resume->getOwner()->getId()!==$loggedInUser->getId()) throw new HttpException(403,'Forbidden'); $all=$this->resumeRepository->findBy(['owner'=>$loggedInUser]); foreach($all as $item){ $item->setIsActive($item->getId()===$resume->getId()); $this->resumeRepository->save($item, false);} $this->resumeRepository->getEntityManager()->flush(); return new JsonResponse(['id'=>$resume->getId(),'active'=>true]); }}
